            task_list.append(task)

    if task_scores:
        mean_score = sum(task_scores.values()) / len(task_scores)
        model_name = model_dir_name.replace('__', '/')
        model_scores[model_name] = {
            'mean': mean_score,
            'n_tasks': len(task_scores),
            'tasks': task_list
        }

sorted_models = sorted(model_scores.items(), key=lambda x: x[1]['mean'], reverse=True)

# Print all with at least 5 tasks, sorted by mean
print(f"Scandinavian MTEB Leaderboard (as of August 2025) - ALL models with 5+ tasks")
print(f"{'Rank':<5} {'Model':<60} {'Mean(Task)*100':<14} {'#Tasks':<8}")
print("-" * 90)
shown = 0
for model, info in sorted_models:
    if info['n_tasks'] >= 5:
        shown += 1
        if shown <= 40:
            print(f"{shown:<5} {model:<60} {info['mean']*100:<14.2f} {info['n_tasks']:<8}")

